export const fetchVendorProducts = async (
	req: Request,
	res: Response,
): Promise<void> => {
	const vendorId = (req as AuthenticatedRequest).user?.id; // Authenticated user ID from middleware
	const { name, sku, status, condition, categoryName } = req.query;

	try {
		const products = await Product.findAll({
			where: { vendorId },
			include: [
				{
					model: SubCategory,
					as: "sub_category",
					where: categoryName ? { name: categoryName } : undefined,
				},
				{
					model: Store,
					as: "store",
					attributes: ["name"],
					include: [
						{
							model: Currency,
							as: "currency",
							attributes: ["symbol"],
						},
					],
				},
			],
			...((name || sku || status || condition) && {
				where: {
					...(name && { name: { [Op.like]: `%${name}%` } }),
					...(sku && { sku }),
					...(status && { status }),
					...(condition && { condition }),
				},
			}),
		});

		res.status(200).json({
			data: products,
		});
	} catch (error) {
		logger.error(error);
		res.status(500).json({ message: "Failed to fetch products" });
	}
};

